StringBuilder reviewRequiredAttribute = new StringBuilder();

string sreviewRequiredFields = _context.XmlVariables["dAttributeMappingCSV"].GetXmlNode("//*").OuterXml;
XmlDocument dreviewRequiredFields = new XmlDocument();
dreviewRequiredFields.LoadXml(sreviewRequiredFields);


XmlNodeList rows = dreviewRequiredFields.SelectNodes("//Row");

foreach (XmlNode row in rows){
	string attributegroupName = row.SelectSingleNode("AttributeGroup").InnerText;
	string attributeFieldName = row.SelectSingleNode("AttributeName").InnerText;
	string Required = row.SelectSingleNode("IsReviewRequired").InnerText;
	if (row != null || !string.IsNullOrEmpty(row.InnerText))
	{
		// Only mark as required if 'Required' from the attributes definition is "yes"
		string requiredSuffix = (Required == "Yes") ? ".#required#" : "";
		reviewRequiredAttribute.Append($"CustomAttributes#.#{attributegroupName}#.#Field#.#{attributeFieldName}#{requiredSuffix}|#");
	}
}

return reviewRequiredAttribute.ToString();

XmlNodeList RoutingOptionsList = _context.XmlVariables["dNextRouteSelection"].GetXmlNodes("//Row");

System.Xml.XmlDocument xWFDataXml = new XmlDocument();
var xWFData = _context.XmlVariables["xWFData"].GetXmlNode("//*").OuterXml;
xWFDataXml.LoadXml(xWFData);
System.Xml.XmlElement root = xWFDataXml.DocumentElement;

System.Xml.XPath.XPathNavigator requestNavigator = xWFDataXml.CreateNavigator();
bool found = false;

foreach(XmlNode RoutingOptionsNode in RoutingOptionsList){

    string condition = RoutingOptionsNode.SelectSingleNode("Condition").InnerText;

    if (condition != "" && !found) {
      System.Xml.XPath.XPathExpression expression = System.Xml.XPath.XPathExpression.Compile(condition);
      if (expression.ReturnType.Equals(System.Xml.XPath.XPathResultType.Boolean)){
        if ((bool)requestNavigator.Evaluate(expression)){

            XmlNode NodeSysRoute =  root.SelectSingleNode("//SYS_Route");
            string sNextRoute = RoutingOptionsNode.SelectSingleNode("NextRoute").InnerText;
            NodeSysRoute.InnerText = sNextRoute;

            found = true;
        }
      }
    }
}

return xWFDataXml.OuterXml;

